import os
import json
from dotenv import load_dotenv
from openai import OpenAI

# Load environment variables from .env file
load_dotenv()

# Set up OpenAI API client
openai = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))

# Define function to validate user input and concatenate with system instructions
def get_response(user_input):
    # Validate untrusted input and use secure platform APIs
    if not user_input:
        return "Please enter a valid message."
    
    # Apply least privilege and explicit allowlists where relevant
    system_instructions = "I'm just an AI, I don't have personal preferences. However, I can assist you with your questions."
    user_input = json.dumps(user_input)
    
    # Keep secrets, tokens, and sensitive data out of plaintext storage and logs
    response = openai.Completion.create(
        engine="content-filter",
        prompt=system_instructions + "\n\n" + user_input,
        temperature=0.5,
        max_tokens=100,
        top_p=1,
        frequency_penalty=0.5,
        presence_penalty=0.2,
        stop=["\n"]
    )
    
    # Return model response directly to user
    return json.loads(response)["choices"][0]["text"].strip()

# Test the function with a sample input
print(get_response("Hello"))